// Parse the episode JSON from OpenAI response
const input = $input.first().json;

// Extract the text content - handle different response shapes
let rawText = input.output || input.text || input.content || '';
if (typeof rawText === 'object') rawText = JSON.stringify(rawText);

// Clean markdown code fences if present
rawText = rawText.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();

let episode;
try {
  episode = JSON.parse(rawText);
} catch (e) {
  // Try to extract JSON from the text
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) {
    episode = JSON.parse(match[0]);
  } else {
    throw new Error('Could not parse episode JSON: ' + e.message);
  }
}

// Validate required fields
if (!episode.scenes || !Array.isArray(episode.scenes)) {
  throw new Error('Episode missing scenes array');
}

// Output one item per scene, each carrying full episode context
const scenes = episode.scenes.map((scene, idx) => ({
  json: {
    episodeNumber: episode.episodeNumber || 1,
    episodeTitle: episode.title || 'Untitled Episode',
    recap: episode.recap || '',
    cliffhanger: episode.cliffhanger || '',
    nextEpisodeTeaser: episode.nextEpisodeTeaser || '',
    totalScenes: episode.scenes.length,
    sceneIndex: idx,
    sceneNumber: scene.sceneNumber || (idx + 1),
    location: scene.location || 'villa',
    characters: scene.characters || [],
    action: scene.action || '',
    dialogue: scene.dialogue || '',
    mood: scene.mood || 'dramatic',
    imagePrompt: scene.imagePrompt || `Pixar-style 3D render, anthropomorphic fruit characters in luxury villa, ${scene.mood || 'dramatic'} lighting, cinematic, colorful, 16:9`,
    fullEpisode: episode
  }
}));

return scenes;

// Collect all scene results with their image URLs
const items = $input.all();
const scenes = [];
let episodeData = null;

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  // Get episode data from first item
  if (!episodeData && item.episodeTitle) {
    episodeData = {
      episodeNumber: item.episodeNumber,
      title: item.episodeTitle,
      recap: item.recap,
      cliffhanger: item.cliffhanger,
      nextEpisodeTeaser: item.nextEpisodeTeaser
    };
  }

  // Extract image URL from OpenAI response
  // DALL-E 3 returns url in the response data
  const imageUrl = item.url || item.data?.[0]?.url || item.image_url || '';

  scenes.push({
    sceneNumber: item.sceneNumber || (i + 1),
    dialogue: item.dialogue || `Scene ${i + 1}`,
    mood: item.mood || 'dramatic',
    location: item.location || 'villa',
    characters: item.characters || [],
    action: item.action || '',
    imageUrl: imageUrl,
    imagePrompt: item.imagePrompt || ''
  });
}

if (!episodeData) {
  episodeData = { episodeNumber: 1, title: 'Fruit Love Island', recap: '', cliffhanger: '', nextEpisodeTeaser: '' };
}

// Build subtitle content (SRT format) for FFmpeg
let srtContent = '';
const secondsPerScene = 5; // 5 seconds per scene image

scenes.forEach((scene, idx) => {
  const startSec = idx * secondsPerScene;
  const endSec = startSec + secondsPerScene;
  const startTime = `00:00:${String(startSec).padStart(2, '0')},000`;
  const endTime = `00:00:${String(endSec).padStart(2, '0')},000`;

  srtContent += `${idx + 1}\n${startTime} --> ${endTime}\n${scene.dialogue}\n\n`;
});

// Build image download + FFmpeg command
const workDir = '/tmp/fruit-love-island';
const imageDownloads = scenes.map((s, i) => 
  s.imageUrl ? `curl -sL "${s.imageUrl}" -o ${workDir}/scene_${i}.png` : `echo "No image for scene ${i}"`
).join(' && ');

const inputFiles = scenes.map((s, i) => 
  `-loop 1 -t ${secondsPerScene} -i ${workDir}/scene_${i}.png`
).join(' ');

const filterParts = scenes.map((s, i) => 
  `[${i}:v]scale=1024:1024,setsar=1[v${i}]`
).join('; ');

const concatInputs = scenes.map((s, i) => `[v${i}]`).join('');
const totalDuration = scenes.length * secondsPerScene;

const ffmpegCmd = `ffmpeg -y ${inputFiles} -filter_complex "${filterParts}; ${concatInputs}concat=n=${scenes.length}:v=1:a=0[outv]" -map "[outv]" -c:v libx264 -pix_fmt yuv420p -r 24 -t ${totalDuration} ${workDir}/episode.mp4`;

const fullCommand = `mkdir -p ${workDir} && ${imageDownloads} && echo '${srtContent.replace(/'/g, "'\\''")}' > ${workDir}/subtitles.srt && ${ffmpegCmd}`;

return [{
  json: {
    ...episodeData,
    scenes: scenes,
    srtContent: srtContent,
    videoCommand: fullCommand,
    videoPath: `${workDir}/episode.mp4`,
    workDir: workDir,
    totalDuration: totalDuration,
    sceneCount: scenes.length
  }
}];

// Combine caption with video path for Facebook upload
const captionItem = $input.first().json;
const caption = captionItem.output || captionItem.text || captionItem.content || 'New episode of Fruit Love Island!';

// Get episode data from previous nodes using $('node name') 
const episodeData = $('Aggregate Scenes & Prepare Video').first().json;

return [{
  json: {
    caption: caption,
    videoPath: episodeData.videoPath || '/tmp/fruit-love-island/episode.mp4',
    episodeTitle: episodeData.title || 'Fruit Love Island',
    episodeNumber: episodeData.episodeNumber || 1,
    sceneCount: episodeData.sceneCount || 6
  }
}];
